SELECT * 
FROM airflow_instances
WHERE environment = 'production' AND is_active = 1;

SELECT dag_name, description
FROM dags
WHERE owner = 'admin' AND last_run_status = 'success';

SELECT history_id, change_description
FROM config_history
WHERE status = 'applied';

SELECT COUNT(*) 
FROM airflow_instances 
WHERE environment = 'development' AND is_active = 1;

SELECT COUNT(DISTINCT a.user_id)
FROM audit_logs AS a
WHERE a.event_type = 'role_change' AND a.event_date >= DATE('now', '-7 day');
